$(function(){$("a.btn-insert-article").on("click",function(){var t=$(this),e=$(".article-title").val(),n=new Date,i=Date.parse(n),a=$(".article-type").find("option:selected").val(),l=$("#elm1").val(),o=$(".article-subtitle").val(),c=t.siblings(".notice-span");if(e.length>0&&l.length>0&&o.length>0){c.html("");var r={title:e,content:l,time:n.toLocaleString(),type:a,parse:i,subtitle:o};$.post("/insertarticle",r,function(t){console.log(t)}),c.html("添加成功！")}else c.html("条件不充分！")}),$("a.btn-update-article").on("click",function(){var t=$(this),e=$(".article-title").val(),n=new Date,i=Date.parse(n),a=$(".article-type").find("option:selected").val(),l=$("#elm1").val(),o=$(".article-title").attr("article-id"),c=t.siblings(".notice-span"),r=$(".article-subtitle").val();e.length>0&&l.length>0&&r.length>0?(c.html(""),$.getJSON("/updatearticle",{_id:o,title:e,content:l,time:n.toLocaleString(),type:a,parse:i,subtitle:r},function(t){console.log(t)}),c.html("更新成功！"),setTimeout(function(){location.replace("/editarticle")},300)):c.html("条件不充分！")});var t=$("a.deleteArticleLink");for(i=0;t.length>i;i++)(function(e){t.eq(e).on("click",function(){var t=$(this);$.getJSON("/deletearticle",{id:t.attr("id")},function(e){var n=e.num;1===n&&t.parent().parent().remove()})})})(i);var e=$("a.deleteCommentsLink");for(i=0;e.length>i;i++)(function(t){e.eq(t).on("click",function(){var t=$(this);$.getJSON("/deletearticlecmts",{id:t.attr("id"),cmnum:t.attr("num"),cmtit:t.attr("tit"),cmct:t.attr("content"),cmtime:t.attr("cttime"),cmtcond:t.attr("cmtscond")},function(e){var n=e.num;1===n&&t.parent().remove()})})})(i)});